// ---------------------------------------------------------------------------
// Simulated catalog data store   (in production: database / ERP gateway)
// ---------------------------------------------------------------------------

const PRODUCTS = [
  { id: 1, name: 'Laptop Pro',      price: 1299, inventory: 42, category: 'Electronics' },
  { id: 2, name: 'Wireless Phone',  price:  799, inventory: 88, category: 'Electronics' },
  { id: 3, name: 'Tablet Air',      price:  549, inventory: 35, category: 'Electronics' },
  { id: 4, name: 'Noise-Cancel Headphones', price: 249, inventory: 120, category: 'Audio'    },
  { id: 5, name: 'Smart Watch',     price:  349, inventory: 67, category: 'Wearables' },
  { id: 6, name: 'Bluetooth Speaker', price:  129, inventory: 94, category: 'Audio'    },
  { id: 7, name: 'USB-C Hub',       price:   59, inventory: 200, category: 'Accessories' },
  { id: 8, name: 'Mechanical Keyboard', price: 179, inventory: 53, category: 'Accessories' },
];

/** Last time the upstream ERP/PIM was polled for changes. */
let lastSyncedAt = '2026-07-01T00:00:00.000Z';

/** Simple counter bumped each sync so we can visually verify changes. */
let syncGeneration = 0;

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Retrieve the current product catalog snapshot.
 * Simulates a ~100 ms database read.
 */
export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));

  return {
    products: PRODUCTS.map((p) => ({ ...p })),
    syncedAt: lastSyncedAt,
    generation: syncGeneration,
  };
}

/**
 * Trigger a full upstream sync (ERP / PIM).
 *
 * Simulates a slow network payload — pricing, inventory, and availability
 * coming in from the upstream system.  In production this would batch-update
 * thousands of SKUs.
 */
export async function syncCatalog() {
  // Simulate the latency of a real ERP integration
  await new Promise((resolve) => setTimeout(resolve, 3_000));

  // ---- upstream data arrives ----
  // Bump generation so the UI can detect that *something* changed
  syncGeneration += 1;

  // Perturb prices slightly to mimic real changes trickling in
  for (const product of PRODUCTS) {
    const delta = Math.round((Math.random() - 0.5) * 40);
    product.price = Math.max(1, product.price + delta);
    product.inventory = Math.max(
      0,
      product.inventory + Math.round((Math.random() - 0.5) * 20)
    );
  }

  lastSyncedAt = new Date().toISOString();

  return { synced: true, timestamp: lastSyncedAt };
}

import { unstable_cache } from 'next/cache';

import { getAllProducts } from './db';

export interface Product {
  id: number;
  name: string;
  price: number;
  inventory: number;
  category: string;
}

export interface CatalogSnapshot {
  products: Product[];
  syncedAt: string;
  generation: number;
}

/**
 * Cached catalog reader.
 *
 * Uses the cache tag `"products"` so that any Server Action or route handler
 * can invalidate this value by calling `revalidateTag("products")`.  All views
 * that depend on the same catalog data share this single cache entry and will
 * be refreshed together on next access after invalidation.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<CatalogSnapshot> => {
    console.log('[products] cache MISS — fetching catalog from DB');
    return getAllProducts();
  },
  // Stable key parts — changing these would create a new cache slot
  ['products-catalog-data'],
  {
    // ── MUST match the tag used by the sync action ──
    tags: ['products'],
  },
);

import { Suspense } from 'react';
import { revalidateTag } from 'next/cache';
import type { Metadata } from 'next';

import { getCachedProducts } from '@/lib/products';
import { syncCatalog } from '@/lib/db';
import { SyncForm } from './sync-form';

export const metadata: Metadata = {
  title: 'Product Catalog — Admin',
};

// ── Inline Server Action ─────────────────────────────────────────────
// Defined in the page so the sync trigger lives right alongside the view.
async function syncAction() {
  'use server';

  console.log('[sync] revalidating products tag — views will refresh on next access');
  revalidateTag('products');

  // Kick off the upstream sync in background.
  // The action returns immediately so the admin can keep working with
  // briefly stale data.  When the sync finishes, cache is invalidated
  // again so all catalog views converge on fresh data.
  syncCatalog()
    .then(() => {
      console.log('[sync] background sync complete — revalidating again');
      revalidateTag('products');
    })
    .catch((err: unknown) => {
      console.error('[sync] background sync failed', err);
    });
}
// ─────────────────────────────────────────────────────────────────────

// ── Loading fallback (rendered inside <Suspense>) ────────────────────
function CatalogSkeleton() {
  return (
    <div style={{ padding: '2rem', textAlign: 'center', color: '#888' }}>
      Loading catalog…
    </div>
  );
}

// ── Product table (the data-dependent part) ──────────────────────────
async function CatalogTable() {
  const { products, syncedAt, generation } = await getCachedProducts();

  return (
    <>
      {/* Sync meta bar */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '1rem',
          fontSize: '0.85rem',
          color: '#555',
        }}
      >
        <span>
          Last synced:{' '}
          <time dateTime={syncedAt}>
            {new Date(syncedAt).toLocaleString('en-US', {
              year: 'numeric',
              month: 'short',
              day: 'numeric',
              hour: '2-digit',
              minute: '2-digit',
              second: '2-digit',
            })}
          </time>
        </span>
        <span
          style={{
            background: '#e8f5e9',
            color: '#2e7d32',
            padding: '0.15rem 0.6rem',
            borderRadius: 999,
            fontWeight: 600,
            fontSize: '0.75rem',
          }}
        >
          generation #{generation}
        </span>
      </div>

      {/* Products table */}
      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            fontSize: '0.9rem',
          }}
        >
          <thead>
            <tr style={{ borderBottom: '2px solid #ddd', textAlign: 'left' }}>
              <th style={thStyle}>SKU</th>
              <th style={thStyle}>Name</th>
              <th style={thStyle}>Category</th>
              <th style={{ ...thStyle, textAlign: 'right' }}>Price</th>
              <th style={{ ...thStyle, textAlign: 'right' }}>Inventory</th>
              <th style={{ ...thStyle, textAlign: 'center' }}>Status</th>
            </tr>
          </thead>
          <tbody>
            {products.map((p) => {
              const status =
                p.inventory === 0
                  ? 'Out of Stock'
                  : p.inventory < 20
                    ? 'Low Stock'
                    : 'In Stock';
              const statusColor =
                p.inventory === 0
                  ? '#d32f2f'
                  : p.inventory < 20
                    ? '#f57c00'
                    : '#2e7d32';
              return (
                <tr
                  key={p.id}
                  style={{ borderBottom: '1px solid #eee' }}
                >
                  <td style={tdStyle}>
                    <code style={{ fontSize: '0.8rem' }}>
                      PRD-{String(p.id).padStart(4, '0')}
                    </code>
                  </td>
                  <td style={tdStyle}>{p.name}</td>
                  <td style={tdStyle}>{p.category}</td>
                  <td style={{ ...tdStyle, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                    ${p.price.toFixed(2)}
                  </td>
                  <td style={{ ...tdStyle, textAlign: 'right' }}>{p.inventory}</td>
                  <td style={{ ...tdStyle, textAlign: 'center' }}>
                    <span
                      style={{
                        display: 'inline-block',
                        padding: '0.1rem 0.5rem',
                        borderRadius: 999,
                        fontSize: '0.75rem',
                        fontWeight: 600,
                        color: '#fff',
                        background: statusColor,
                      }}
                    >
                      {status}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {products.length === 0 && (
        <p style={{ textAlign: 'center', color: '#999', marginTop: '2rem' }}>
          No products found.
        </p>
      )}
    </>
  );
}

// ── Page component ───────────────────────────────────────────────────
export default async function AdminProductsPage() {
  return (
    <main
      style={{
        maxWidth: 960,
        margin: '0 auto',
        padding: '2rem 1.5rem',
        fontFamily:
          '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif',
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '0.5rem',
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: '1.6rem', fontWeight: 700 }}>
            Product Catalog
          </h1>
          <p style={{ margin: '0.25rem 0 0', color: '#666', fontSize: '0.9rem' }}>
