import { SyncForm } from './sync-form';

export const metadata: Metadata = {
  title: 'Product Catalog — Admin',
};

// ── Inline Server Action ─────────────────────────────────────────────
// Defined in the page so the sync trigger lives right alongside the view.
async function syncAction() {
  'use server';

  console.log('[sync] revalidating products tag — views will refresh on next access');
  revalidateTag('products');

  // Kick off the upstream sync in background.
  // The action returns immediately so the admin can keep working with
  // briefly stale data.  When the sync finishes, cache is invalidated
  // again so all catalog views converge on fresh data.
  syncCatalog()
    .then(() => {
      console.log('[sync] background sync complete — revalidating again');
      revalidateTag('products');
    })
    .catch((err: unknown) => {
      console.error('[sync] background sync failed', err);
    });
}

