import { Suspense } from 'react';
import { updateTag } from 'next/cache';
import type { Metadata } from 'next';

import { getCachedProducts } from '@/lib/products';
import { syncCatalog } from '@/lib/db';
import { SyncForm } from './sync-form';

export const metadata: Metadata = {
  title: 'Product Catalog — Admin',
};

// ── Inline Server Action ─────────────────────────────────────────────
// Defined in the page so the sync trigger lives right alongside the view.
async function syncAction() {
  'use server';

  try {
    // 1. Run the upstream sync — simulates a slow ERP/PIM data pull.
    await syncCatalog();

    // 2. Invalidate the "products" cache tag so every view that depends on
    //    the catalog picks up the fresh data on next access.  `updateTag`
    //    is the Server Action–friendly equivalent of `revalidateTag` in
    //    Next.js 16+ with read-your-own-writes semantics.
    console.log('[sync] catalog updated — invalidating "products" tag');
    updateTag('products');
  } catch (err) {
    console.error('[sync] sync action failed', err);
    // Re-throw so Next.js surfaces the error to the form.
    throw new Error('Catalog sync failed. Please try again.');
  }
}
// ─────────────────────────────────────────────────────────────────────

// ── Loading fallback (rendered inside <Suspense>) ────────────────────
function CatalogSkeleton() {
  return (
    <div style={{ padding: '2rem', textAlign: 'center', color: '#888' }}>
      Loading catalog…
    </div>
  );
}

// ── Product table (the data-dependent part) ──────────────────────────
async function CatalogTable() {
  const { products, syncedAt, generation } = await getCachedProducts();

  return (
    <>
      {/* Sync meta bar */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '1rem',
          fontSize: '0.85rem',
          color: '#555',
        }}
      >
        <span>
          Last synced:{' '}
          <time dateTime={syncedAt}>
            {new Date(syncedAt).toLocaleString('en-US', {
              year: 'numeric',
              month: 'short',
              day: 'numeric',
              hour: '2-digit',
              minute: '2-digit',
              second: '2-digit',
            })}
          </time>
        </span>
        <span
          style={{
            background: '#e8f5e9',
            color: '#2e7d32',
            padding: '0.15rem 0.6rem',
            borderRadius: 999,
            fontWeight: 600,
            fontSize: '0.75rem',
          }}
        >
          generation #{generation}
        </span>
      </div>

      {/* Products table */}
      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            fontSize: '0.9rem',
          }}
        >
          <thead>
            <tr style={{ borderBottom: '2px solid #ddd', textAlign: 'left' }}>
              <th style={thStyle}>SKU</th>
              <th style={thStyle}>Name</th>
              <th style={thStyle}>Category</th>
              <th style={{ ...thStyle, textAlign: 'right' }}>Price</th>
              <th style={{ ...thStyle, textAlign: 'right' }}>Inventory</th>
              <th style={{ ...thStyle, textAlign: 'center' }}>Status</th>
            </tr>
          </thead>
          <tbody>
            {products.map((p) => {
              const status =
                p.inventory === 0
                  ? 'Out of Stock'
                  : p.inventory < 20
                    ? 'Low Stock'
                    : 'In Stock';
              const statusColor =
                p.inventory === 0
                  ? '#d32f2f'
                  : p.inventory < 20
                    ? '#f57c00'
                    : '#2e7d32';
              return (
                <tr
                  key={p.id}
                  style={{ borderBottom: '1px solid #eee' }}
                >
                  <td style={tdStyle}>
                    <code style={{ fontSize: '0.8rem' }}>
                      PRD-{String(p.id).padStart(4, '0')}
                    </code>
                  </td>
                  <td style={tdStyle}>{p.name}</td>
                  <td style={tdStyle}>{p.category}</td>
                  <td style={{ ...tdStyle, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                    ${p.price.toFixed(2)}
                  </td>
                  <td style={{ ...tdStyle, textAlign: 'right' }}>{p.inventory}</td>
                  <td style={{ ...tdStyle, textAlign: 'center' }}>
                    <span
                      style={{
                        display: 'inline-block',
                        padding: '0.1rem 0.5rem',
                        borderRadius: 999,
                        fontSize: '0.75rem',
                        fontWeight: 600,
                        color: '#fff',
                        background: statusColor,
                      }}
                    >
                      {status}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {products.length === 0 && (
        <p style={{ textAlign: 'center', color: '#999', marginTop: '2rem' }}>
          No products found.
        </p>
      )}
    </>
  );
}

// ── Page component ───────────────────────────────────────────────────
export default async function AdminProductsPage() {
  return (
    <main
      style={{
        maxWidth: 960,
        margin: '0 auto',
        padding: '2rem 1.5rem',
        fontFamily:
          '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif',
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '0.5rem',
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: '1.6rem', fontWeight: 700 }}>
            Product Catalog
          </h1>
          <p style={{ margin: '0.25rem 0 0', color: '#666', fontSize: '0.9rem' }}>
            Browse, search, and manage products.  Data is cached for fast
            day-to-day browsing.
          </p>
        </div>
      </div>

      {/* Sync action — regular HTML form, progressively enhanced */}
      <div
        style={{
          background: '#f8f9fa',
          border: '1px solid #e9ecef',
          borderRadius: 8,
          padding: '1rem 1.25rem',
          marginBottom: '1.5rem',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '1rem',
        }}
      >
        <div>
          <p style={{ margin: 0, fontWeight: 600, fontSize: '0.9rem' }}>
            Catalog source
          </p>
          <p style={{ margin: '0.2rem 0 0', fontSize: '0.8rem', color: '#666' }}>
            Pricing and inventory originate from the upstream ERP/PIM.
            Sync pulls the latest changes.
          </p>
        </div>
        <SyncForm action={syncAction} />
      </div>

      {/* Product list with Suspense for progressive rendering */}
      <Suspense fallback={<CatalogSkeleton />}>
        <CatalogTable />
      </Suspense>
    </main>
  );
}

// ── Shared inline styles ─────────────────────────────────────────────
const thStyle: React.CSSProperties = {
  padding: '0.6rem 0.75rem',
  fontWeight: 600,
  fontSize: '0.8rem',
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
  color: '#555',
};

const tdStyle: React.CSSProperties = {
  padding: '0.65rem 0.75rem',
};

